import React from 'react';
import { motion } from 'framer-motion';
import { FaUser, FaEnvelope, FaCommentDots, FaPaperPlane } from 'react-icons/fa';

const Contact = () => (
  <motion.main 
    initial={{opacity:0, y:30}} 
    animate={{opacity:1, y:0}} 
    transition={{duration:0.8}}
    style={{
      background: 'linear-gradient(135deg, #e0e7ff 0%, #f0fdf4 60%, #fef9c3 100%)',
      borderRadius: '24px',
      boxShadow: '0 8px 32px rgba(99,102,241,0.10)',
      padding: '2.5rem 2rem',
      margin: '2.5rem auto',
      maxWidth: 480
    }}
  >
    <h2 style={{textAlign:'center', color:'#23254c', fontSize:'2rem', marginBottom:'2rem', fontWeight:700}}>Contact <span style={{color:'#6366f1'}}>Us</span></h2>
    <motion.form 
      className="contact-form vibrant"
      initial={{ opacity: 0, y: 30 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.7, delay: 0.2 }}
      style={{
        background:'rgba(255,255,255,0.95)',
        borderRadius:'18px',
        boxShadow:'0 2px 8px rgba(99,102,241,0.10)',
        padding:'2rem 1.2rem',
        display:'flex',
        flexDirection:'column',
        gap:'1.3rem'
      }}
    >
      <label style={{display:'flex', alignItems:'center', gap:'0.7rem', color:'#6366f1', fontWeight:500}}>
        <FaUser size={18}/> Name
        <input type="text" name="name" required style={{flex:1, padding:'0.7rem', borderRadius:'8px', border:'1.5px solid #6366f1', fontSize:'1.07rem'}}/>
      </label>
      <label style={{display:'flex', alignItems:'center', gap:'0.7rem', color:'#22c55e', fontWeight:500}}>
        <FaEnvelope size={18}/> Email
        <input type="email" name="email" required style={{flex:1, padding:'0.7rem', borderRadius:'8px', border:'1.5px solid #22c55e', fontSize:'1.07rem'}}/>
      </label>
      <label style={{display:'flex', alignItems:'center', gap:'0.7rem', color:'#f59e42', fontWeight:500}}>
        <FaCommentDots size={18}/> Message
        <textarea name="message" rows="4" required style={{flex:1, padding:'0.7rem', borderRadius:'8px', border:'1.5px solid #f59e42', fontSize:'1.07rem'}}></textarea>
      </label>
      <button type="submit" style={{
        background:'linear-gradient(90deg, #6366f1 0%, #22c55e 100%)',
        color:'#fff',
        border:'none',
        padding:'0.85rem 2rem',
        borderRadius:'999px',
        fontSize:'1.12rem',
        fontWeight:700,
        cursor:'pointer',
        marginTop:'1.2rem',
        boxShadow:'0 2px 8px rgba(99,102,241,0.13)',
        letterSpacing:'0.01em',
        display:'inline-flex',
        alignItems:'center',
        gap:'0.7rem',
        transition:'background 0.25s, transform 0.18s'
      }}>
        <FaPaperPlane /> Send
      </button>
    </motion.form>
  </motion.main>
);

export default Contact;
